<template>
    <div>
        <div class="content">
            <el-card v-loading="loading" style="width: 30rem">
                <h2>template-vue2-element</h2>
                <el-tabs v-model="form.type">
                    <el-tab-pane label="密码登录" name="password"/>
                    <el-tab-pane label="短信登录" name="code"/>
                </el-tabs>
                <el-form size="large">
                    <el-form-item>
                        <el-input v-model="form.mobile" prefix-icon="el-icon-mobile" placeholder="手机号码" clearable></el-input>
                    </el-form-item>
                    <el-form-item v-if="form.type==='password'">
                        <el-input v-model="form.password" prefix-icon="el-icon-key" placeholder="密码" clearable></el-input>
                    </el-form-item>
                    <el-form-item v-if="form.type==='code'">
                        <el-input v-model="form.vcode" prefix-icon="el-icon-key" placeholder="验证码" clearable>
                            <template slot="append">
                                <el-button v-if="countDown < 0" @click="send">获取验证码</el-button>
                                <el-button v-else disabled>{{`${countDown}秒后重新获取`}}</el-button>
                            </template>
                        </el-input>
                    </el-form-item>
                    <el-form-item>
                        <el-checkbox v-model="form.remember" :style="{visibility : form.type==='code' ? 'hidden' : 'visible'}">记住密码</el-checkbox>
                        <el-button class="w-100 m-0" type="primary" @click="login">登录</el-button>
                        <el-button class="w-100 m-0" type="text">注册</el-button>
                    </el-form-item>
                </el-form>
            </el-card>
        </div>
        <Footer></Footer>
    </div>
</template>
<script>
    import Footer from "@/components/layout/Footer";
    import CustomStorage from "@/plugins/common/CustomStorage";

    export default {
        data() {
            return {
                loading: false,
                form: {type: 'password'},
                countDown: -1,
                interval: null
            }
        },
        methods: {
            login() {
                this.$router.push({name: 'main'});
                CustomStorage.clear();
                CustomStorage.setItem('_is_from_login', 1);
                this.$store.commit('setActiveIndex', '');
            },
            send() {
                this.countDown = 60;
                this.interval = setInterval(() => {
                    clearInterval(this.countDown-- > 0 || this.interval);
                }, 1000);
            }
        },
        beforeDestroy() {
            clearInterval(this.interval);
        },
        components: {Footer},
    }
</script>

<style scoped>
    .content {
        height: 80vh;
        display: flex;
        justify-content: center; /* 水平居中 */
        align-items: center; /* 垂直居中 */
    }

    @media screen and (max-width: 991px) {
        .el-card {
            border: none;
            box-shadow: none;
        }
    }
</style>
